from flask import Flask, redirect, request, session, url_for, jsonify
from urllib.parse import urlencode
import os
import secrets

app = Flask(__name__)
app.secret_key = os.getenv("FLASK_SECRET_KEY", secrets.token_hex(32))

OIDC_AUTHORIZATION_ENDPOINT = os.getenv("OIDC_AUTHORIZATION_ENDPOINT", "https://example.com/oauth2/authorize")
OIDC_CLIENT_ID = os.getenv("OIDC_CLIENT_ID", "your-client-id")
OIDC_REDIRECT_URI = os.getenv("OIDC_REDIRECT_URI", "http://localhost:5000/callback")
OIDC_SCOPE = "openid"


@app.route("/")
def index():
    if "id_token" in session:
        return jsonify(
            {
                "authenticated": True,
                "id_token": session["id_token"],
                "state": session.get("state"),
            }
        )
    return jsonify({"authenticated": False, "login_url": url_for("login", _external=True)})


@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["state"] = state

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": OIDC_SCOPE,
        "response_type": "id_token",
        "state": state,
    }

    return redirect(f"{OIDC_AUTHORIZATION_ENDPOINT}?{urlencode(params)}")


@app.route("/callback")
def callback():
    returned_state = request.args.get("state")
    if not returned_state or returned_state != session.get("state"):
        return jsonify({"error": "invalid_state"}), 400

    id_token = request.args.get("id_token")
    if not id_token:
        return jsonify(
            {
                "error": "missing_id_token",
                "detail": "For response_type=id_token, many providers return the token in the URL fragment, which is not sent to the server.",
            }
        ), 400

    session["id_token"] = id_token
    return redirect(url_for("profile"))


@app.route("/profile")
def profile():
    if "id_token" not in session:
        return redirect(url_for("login"))
    return jsonify({"authenticated": True, "id_token": session["id_token"]})


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")), debug=True)